        if (frm.doc.custom_has_prescription) {
            if (!frm.doc.custom_bandhu_prescription || frm.doc.custom_bandhu_prescription.length === 0) {
                frappe.throw("Add at least one Medicine in Prescription when 'Has Prescription' is checked.");
            }
        }

        // 🔹 REFERRAL VALIDATION
        // if (frm.doc.custom_has_referral) {
        //     frappe.throw("Please create a Referral before saving when 'Has Referral' is checked.");
