frappe.ui.form.on('Prescription', {

    dosage_frequency: function(frm, cdt, cdn) {
        calculate_qty(frm, cdt, cdn);
    },

    duration_days: function(frm, cdt, cdn) {
        calculate_qty(frm, cdt, cdn);
    }

});


function calculate_qty(frm, cdt, cdn) {
    let row = locals[cdt][cdn];

    let freq_map = {
        "OD": 1,
        "BD": 2,
        "TID": 3,
        "QID": 4
    };

    let per_day = freq_map[row.dosage_frequency] || 0;
    let days = row.duration_days || 0;

    row.quantity = per_day * days;

    frm.refresh_field('bandhu_prescription'); // <-- child table fieldname in parent
}

