frappe.ui.form.on('Patient', {

    // 🔹 Live cleaning (typing time)
    custom_abha_id(frm) {
        let abha = frm.doc.custom_abha_id || "";

        // remove everything except digits
        abha = abha.replace(/\D/g, '');

        // limit to 14 digits
        if (abha.length > 14) {
            abha = abha.slice(0, 14);
        }

        // set cleaned value (only if changed to avoid loop)
        if (abha !== frm.doc.custom_abha_id) {
            frm.set_value('custom_abha_id', abha);
        }
    },

    // 🔹 Final validation (before save)
    async validate(frm) {
        let abha = frm.doc.custom_abha_id;

        if (abha) {

            // final strict check
            if (!/^\d{14}$/.test(abha)) {
                frappe.throw("ABHA ID must be exactly 14 digits (numbers only)");
            }
        }
    }
});

