frappe.ui.form.on('Patient Encounter', {

    custom_location: function(frm) {
        frm.trigger("fetch_location_details");
    },

    fetch_location_details: async function(frm) {

        if (!frm.doc.custom_location) return;

        let location = await frappe.db.get_doc(
            'Bandhu Location',
            frm.doc.custom_location
        );

        frm.set_value('custom_lsg', location.lsg);
        frm.set_value('custom_district', location.district);
        frm.set_value('custom_state', location.state);
    }

});

