frappe.ui.form.on('Patient', {
    validate(frm) {

        function validate_mobile(value) {
            if (!value) {
                frappe.throw("Mobile number is required");
            }

            value = value.toString().trim();

            if (!/^\d{10}$/.test(value)) {
                frappe.throw("Mobile number must be exactly 10 digits");
            }
        }

        function validate_phone(value) {
            if (!value) return; // optional

            value = value.toString().trim();

            if (!/^\d{10}$/.test(value)) {
                frappe.throw("Phone number must be exactly 10 digits");
            }
        }

        validate_mobile(frm.doc.mobile);
        validate_phone(frm.doc.phone);
    }
});

